    'Full body strength and cardio combination workouts with positive coaching energy',
    'Viral TikTok Programs'
FROM program_variants pv
JOIN branded_programs bp ON bp.id = pv.base_program_id
WHERE bp.name = 'Sydney Cummings Full Body'
  AND pv.duration_weeks = 12
  AND pv.sessions_per_week = 6
ON CONFLICT DO NOTHING;
